1	/**
2	 * tRPC HTTP Response Handler for App Router
3	 * @see https://trpc.io/docs/v11/adapters/fetch
4	 */
5	import { fetchRequestHandler } from "@trpc/server/adapters/fetch";
6	import { appRouter } from "@/server/index";
7	import { createContext } from "@/server/context";
8	import { cookies } from "next/headers";
9	
10	// Cookie configuration
11	const COOKIE_NAME = "token";
12	const COOKIE_MAX_AGE = 7 * 24 * 60 * 60; // 7 days
13	
14	/**
15	 * Set auth cookie on successful login
16	 */
17	function setAuthCookie(response: Response, token: string): Response {
18	  const headers = new Headers(response.headers);
19	  const isProduction = process.env.NODE_ENV === "production";
20	  
21	  headers.set("Set-Cookie", [
22	    `${COOKIE_NAME}=${token}`,
23	    "Path=/",
24	    `Max-Age=${COOKIE_MAX_AGE}`,
25	    "SameSite=Lax",
26	    "HttpOnly",
27	    ...(isProduction ? ["Secure"] : []),
28	  ].join("; "));
29	  
30	  return new Response(response.body, { status: response.status, headers });
31	}
32	
33	/**
34	 * Clear auth cookie on logout
35	 */
36	function clearAuthCookie(response: Response): Response {
37	  const headers = new Headers(response.headers);
38	  headers.set("Set-Cookie", `${COOKIE_NAME}=; Path=/; Max-Age=0; SameSite=Lax; HttpOnly`);
39	  return new Response(response.body, { status: response.status, headers });
40	}
41	
42	/**
43	 * Extract token from TRPC response data
44	 */
45	function extractToken(data: unknown): string | null {
46	  if (!data || typeof data !== "object") return null;
47	  if (Array.isArray(data)) return extractToken(data[0]);
48	  
49	  const obj = data as Record<string, unknown>;
50	  const token = (obj.result as Record<string, unknown>)?.data as Record<string, unknown>;
51	  return typeof token?.token === "string" ? token.token : null;
52	}
53	
54	/**
55	 * Main handler
56	 */
57	const handler = async (req: Request): Promise<Response> => {
58	  const url = new URL(req.url);
59	  const procedurePath = url.pathname.split("/api/trpc/")[1] ?? "";
60	
61	  const response = await fetchRequestHandler({
62	    endpoint: "/api/trpc",
63	    req,
64	    router: appRouter,
65	    createContext,
66	    /**
67	     * @see https://trpc.io/docs/v11/error-handling
68	     */
69	    onError({ error }) {
70	      if (error.code === "INTERNAL_SERVER_ERROR") {
71	        console.error("tRPC Internal Error:", error);
72	      }
73	    },
74	  });
75	
76	  // Handle auth cookie management
77	  if (procedurePath === "auth.logout") {
78	    return clearAuthCookie(response);
79	  }
80	
81	  if (procedurePath === "auth.login") {
82	    try {
83	      const data = await response.clone().json();
84	      const token = extractToken(data);
85	      if (token) return setAuthCookie(response, token);
86	    } catch {
87	      // Ignore parse errors
88	    }
89	  }
90	
91	  return response;
92	};
93	
94	export { handler as GET, handler as POST };
