1	import { initTRPC, TRPCError } from "@trpc/server";
2	import type { Context } from "./context";
3	import { db } from "@/db/db";
4	import { organizations, organizationMembers } from "@/db/schema";
5	import { eq, and } from "drizzle-orm";
6	import { apiRateLimiter } from "@/lib/rate-limiter";
7	
8	const t = initTRPC.context<Context>().create();
9	
10	export const router = t.router;
11	export const publicProcedure = t.procedure;
12	
13	// Rate limiting middleware for API routes
14	const rateLimitMiddleware = t.middleware(async ({ ctx, next }) => {
15	  const rateLimitResult = await apiRateLimiter.check(ctx.clientIp);
16	  
17	  if (!rateLimitResult.allowed) {
18	    throw new TRPCError({
19	      code: "TOO_MANY_REQUESTS",
20	      message: `Rate limit exceeded. Try again in ${rateLimitResult.resetTime - Math.floor(Date.now() / 1000)} seconds.`,
21	    });
22	  }
23	
24	  return next({ ctx });
25	});
26	
27	export const protectedProcedure = t.procedure
28	  .use(rateLimitMiddleware)
29	  .use(async ({ ctx, next }) => {
30	    if (!ctx.userId) {
31	      throw new TRPCError({
32	        code: "UNAUTHORIZED",
33	        message: "You must be logged in",
34	      });
35	    }
36	
37	    return next({
38	      ctx: {
39	        ...ctx,
40	        userId: ctx.userId,
41	      },
42	    });
43	  });
44	
45	import { z } from "zod";
46	
47	export const organizationProcedure = protectedProcedure
48	  .input(
49	    z.object({
50	      organizationId: z.string().uuid(),
51	    })
52	  )
53	  .use(async ({ ctx, input, next }) => {
54	    // Check if organization exists
55	    const organization = await db.query.organizations.findFirst({
56	      where: eq(organizations.id, input.organizationId),
57	    });
58	
59	    if (!organization) {
60	      throw new TRPCError({
61	        code: "NOT_FOUND",
62	        message: "Organization not found",
63	      });
64	    }
65	
66	    // Check if user is a member of the organization
67	    const membership = await db.query.organizationMembers.findFirst({
68	      where: and(
69	        eq(organizationMembers.organizationId, input.organizationId),
70	        eq(organizationMembers.userId, ctx.userId!)
71	      ),
72	    });
73	
74	    if (!membership) {
75	      throw new TRPCError({
76	        code: "FORBIDDEN",
77	        message: "You are not a member of this organization",
78	      });
79	    }
80	
81	    return next({
82	      ctx: {
83	        ...ctx,
84	        organization,
85	        membership,
86	      },
87	    });
88	  });
