3	import { cookies, headers } from "next/headers";
4	
5	export interface Context {
6	  db: typeof db;
7	  userId: string | null;
8	  clientIp: string;
9	}
10	
11	export async function createContext(): Promise<Context> {
12	  const cookieStore = await cookies();
13	  const headerStore = await headers();
14	  const token = cookieStore.get("token")?.value;
15	  
16	  let userId: string | null = null;
17	  
18	  if (token) {
19	    const payload = verifyToken(token);
20	    userId = payload?.userId ?? null;
21	  }
22	
23	  // Extract client IP for rate limiting
24	  const clientIp = headerStore.get("x-forwarded-for")?.split(",")[0].trim() ||
25	                   headerStore.get("x-real-ip") ||
26	                   "unknown";
27	
28	  return { db, userId, clientIp };
29	}
