1	import { z } from "zod";
2	import { router, publicProcedure } from "../trpc";
3	import { db } from "@/db/db";
4	import { users } from "@/db/schema";
5	import { eq } from "drizzle-orm";
6	import { TRPCError } from "@trpc/server";
7	import bcrypt from "bcryptjs";
8	import { signToken } from "@/lib/jwt";
9	
10	export const authRouter = router({
11	  register: publicProcedure
12	    .input(
13	      z.object({
14	        email: z.string().email(),
15	        password: z.string().min(8),
16	        name: z.string().min(1),
17	      })
18	    )
19	    .mutation(async ({ ctx, input }) => {
20	      const existingUser = await db.query.users.findFirst({
21	        where: eq(users.email, input.email),
22	      });
23	
24	      if (existingUser) {
25	        throw new TRPCError({
26	          code: "CONFLICT",
27	          message: "User with this email already exists",
28	        });
29	      }
30	
31	      const passwordHash = await bcrypt.hash(input.password, 10);
32	
33	      const [user] = await db
34	        .insert(users)
35	        .values({
36	          email: input.email,
37	          passwordHash,
38	          name: input.name,
39	          isActive: true,
40	        })
41	        .returning();
42	
43	      return {
44	        id: user.id,
45	        email: user.email,
46	        name: user.name,
47	      };
48	    }),
49	
50	  login: publicProcedure
51	    .input(
52	      z.object({
53	        email: z.string().email(),
54	        password: z.string(),
55	      })
56	    )
57	    .mutation(async ({ ctx, input }) => {
58	      const user = await db.query.users.findFirst({
59	        where: eq(users.email, input.email),
60	      });
61	
62	      if (!user || !user.passwordHash) {
63	        throw new TRPCError({
64	          code: "UNAUTHORIZED",
65	          message: "Invalid email or password",
66	        });
67	      }
68	
69	      const isValidPassword = await bcrypt.compare(
70	        input.password,
71	        user.passwordHash
72	      );
73	
74	      if (!isValidPassword) {
75	        throw new TRPCError({
76	          code: "UNAUTHORIZED",
77	          message: "Invalid email or password",
78	        });
79	      }
80	
81	      if (!user.isActive) {
82	        throw new TRPCError({
83	          code: "FORBIDDEN",
84	          message: "Account is inactive",
85	        });
86	      }
87	
88	      const token = signToken({
89	        userId: user.id,
90	        email: user.email,
91	      });
92	
93	      return {
94	        id: user.id,
95	        email: user.email,
96	        name: user.name,
97	        token,
98	      };
99	    }),
100	
101	  logout: publicProcedure.mutation(async () => {
102	    return { success: true };
103	  }),
104	
105	  me: publicProcedure.query(async ({ ctx }) => {
106	    if (!ctx.userId) {
107	      return null;
108	    }
109	
110	    const user = await db.query.users.findFirst({
111	      where: eq(users.id, ctx.userId),
112	    });
113	
114	    if (!user || !user.isActive) {
115	      return null;
116	    }
117	
118	    return {
119	      id: user.id,
120	      email: user.email,
121	      name: user.name,
122	    };
123	  }),
124	});
