1	import { z } from "zod";
2	import { router, protectedProcedure, organizationProcedure } from "../trpc";
3	import { db } from "@/db/db";
4	import { organizations, organizationMembers, organizationInvites } from "@/db/schema";
5	import { eq, and } from "drizzle-orm";
6	import { TRPCError } from "@trpc/server";
7	
8	export const organizationsRouter = router({
9	  // Get all organizations for current user
10	  list: protectedProcedure.query(async ({ ctx }) => {
11	    const memberships = await db.query.organizationMembers.findMany({
12	      where: eq(organizationMembers.userId, ctx.userId!),
13	      with: {
14	        organization: true,
15	      },
16	      orderBy: (members, { desc }) => [desc(members.joinedAt)],
17	    });
18	
19	    return memberships.map((m) => m.organization);
20	  }),
21	
22	  // Get single organization by ID
23	  getById: protectedProcedure
24	    .input(z.object({ id: z.string().uuid() }))
25	    .query(async ({ ctx, input }) => {
26	      const membership = await db.query.organizationMembers.findFirst({
27	        where: and(
28	          eq(organizationMembers.organizationId, input.id),
29	          eq(organizationMembers.userId, ctx.userId!)
30	        ),
31	        with: {
32	          organization: true,
33	        },
34	      });
35	
36	      if (!membership) {
37	        throw new TRPCError({
38	          code: "NOT_FOUND",
39	          message: "Organization not found or you are not a member",
40	        });
41	      }
42	
43	      return membership.organization;
44	    }),
45	
46	  // Get organization by slug (only if user is a member)
47	  getBySlug: protectedProcedure
48	    .input(z.object({ slug: z.string() }))
49	    .query(async ({ ctx, input }) => {
50	      const org = await db.query.organizations.findFirst({
51	        where: eq(organizations.slug, input.slug),
52	      });
53	
54	      if (!org) {
55	        throw new TRPCError({ code: "NOT_FOUND", message: "Organization not found" });
56	      }
57	
58	      // Verify the requesting user is a member of this organization
59	      const membership = await db.query.organizationMembers.findFirst({
60	        where: and(
61	          eq(organizationMembers.userId, ctx.userId!),
62	          eq(organizationMembers.organizationId, org.id)
63	        ),
64	      });
65	
66	      if (!membership) {
67	        throw new TRPCError({ code: "NOT_FOUND", message: "Organization not found" });
68	      }
69	
70	      return org;
71	    }),
72	
73	  // Check slug availability and suggest alternative
74	  checkSlugAvailability: protectedProcedure
75	    .input(z.object({ slug: z.string() }))
76	    .query(async ({ ctx, input }) => {
77	      if (!input.slug || input.slug.length === 0) {
78	        return {
79	          available: false,
80	          suggestedSlug: null,
81	        };
82	      }
83	
84	      const existing = await db.query.organizations.findFirst({
85	        where: eq(organizations.slug, input.slug),
86	      });
87	
88	      if (!existing) {
89	        return {
90	          available: true,
91	          suggestedSlug: null,
92	        };
93	      }
94	
95	      let counter = 1;
96	      let suggestedSlug = `${input.slug}-${counter}`;
97	      let isAvailable = false;
98	
99	      while (!isAvailable && counter < 100) {
100	        const check = await db.query.organizations.findFirst({
101	          where: eq(organizations.slug, suggestedSlug),
102	        });
103	
104	        if (!check) {
105	          isAvailable = true;
106	        } else {
107	          counter++;
108	          suggestedSlug = `${input.slug}-${counter}`;
109	        }
110	      }
111	
112	      return {
113	        available: false,
114	        suggestedSlug: isAvailable ? suggestedSlug : null,
115	      };
116	    }),
117	
118	  // Create new organization
119	  create: protectedProcedure
120	    .input(
121	      z.object({
122	        name: z.string().min(1),
123	        slug: z.string().min(1),
124	        description: z.string().optional(),
125	      })
126	    )
127	    .mutation(async ({ ctx, input }) => {
128	      const existing = await db.query.organizations.findFirst({
129	        where: eq(organizations.slug, input.slug),
130	      });
131	
132	      if (existing) {
133	        let counter = 1;
134	        let suggestedSlug = `${input.slug}-${counter}`;
135	        let isAvailable = false;
136	
137	        while (!isAvailable && counter < 100) {
138	          const check = await db.query.organizations.findFirst({
139	            where: eq(organizations.slug, suggestedSlug),
140	          });
141	
142	          if (!check) {
143	            isAvailable = true;
144	          } else {
145	            counter++;
146	            suggestedSlug = `${input.slug}-${counter}`;
147	          }
148	        }
149	
150	        throw new TRPCError({
151	          code: "CONFLICT",
152	          message: `Slug "${input.slug}" is already taken. ${
153	            isAvailable
154	              ? `Suggested: "${suggestedSlug}"`
155	              : "Please choose a different slug."
156	          }`,
157	        });
158	      }
159	
160	      const [org] = await db
161	        .insert(organizations)
162	        .values({
163	          name: input.name,
164	          slug: input.slug,
165	          description: input.description,
166	        })
167	        .returning();
168	
169	      await db.insert(organizationMembers).values({
170	        organizationId: org.id,
171	        userId: ctx.userId!,
172	        role: "owner",
173	      });
174	
175	      return org;
176	    }),
177	
178	  // Update organization
179	  update: organizationProcedure
180	    .input(
181	      z.object({
182	        name: z.string().min(1).optional(),
183	        slug: z.string().min(1).optional(),
184	        description: z.string().optional(),
185	        settings: z.record(z.string(), z.unknown()).optional(),
186	      })
187	    )
188	    .mutation(async ({ ctx, input }) => {
189	      const [updated] = await db
190	        .update(organizations)
191	        .set({
192	          ...input,
193	          updatedAt: new Date(),
194	        })
195	        .where(eq(organizations.id, ctx.organization.id))
196	        .returning();
197	
198	      return updated;
199	    }),
200	
201	  // Delete organization
202	  delete: organizationProcedure.mutation(async ({ ctx }) => {
203	    await db
204	      .delete(organizations)
205	      .where(eq(organizations.id, ctx.organization.id));
206	
207	    return { success: true };
208	  }),
209	
210	  // Get organization members
211	  getMembers: organizationProcedure.query(async ({ ctx }) => {
212	    return await db.query.organizationMembers.findMany({
213	      where: eq(organizationMembers.organizationId, ctx.organization.id),
214	      with: {
215	        user: true,
216	      },
217	    });
218	  }),
219	
220	  // Remove member from organization
221	  removeMember: organizationProcedure
222	    .input(z.object({ memberId: z.string().uuid() }))
223	    .mutation(async ({ ctx, input }) => {
224	      // Only owner/admin can remove members
225	      if (ctx.membership.role !== "owner" && ctx.membership.role !== "admin") {
226	        throw new TRPCError({
227	          code: "FORBIDDEN",
228	          message: "Only owners and admins can remove members",
229	        });
230	      }
231	
232	      // Get the member to remove
233	      const memberToRemove = await db.query.organizationMembers.findFirst({
234	        where: and(
235	          eq(organizationMembers.id, input.memberId),
236	          eq(organizationMembers.organizationId, ctx.organization.id)
237	        ),
238	      });
239	
240	      if (!memberToRemove) {
241	        throw new TRPCError({
242	          code: "NOT_FOUND",
243	          message: "Member not found",
244	        });
245	      }
246	
247	      // Prevent removing the last owner
248	      if (memberToRemove.role === "owner") {
249	        const ownerCount = await db.query.organizationMembers.findMany({
250	          where: and(
251	            eq(organizationMembers.organizationId, ctx.organization.id),
252	            eq(organizationMembers.role, "owner")
253	          ),
254	        });
255	
256	        if (ownerCount.length <= 1) {
257	          throw new TRPCError({
258	            code: "BAD_REQUEST",
259	            message: "Cannot remove the last owner of the organization",
260	          });
261	        }
262	      }
263	
264	      await db
265	        .delete(organizationMembers)
266	        .where(eq(organizationMembers.id, input.memberId));
267	
268	      return { success: true };
269	    }),
270	
271	  // Create invite link
272	  createInviteLink: organizationProcedure
273	    .input(
274	      z.object({
275	        role: z.enum(["admin", "member", "viewer"]).default("member"),
276	        expiresInDays: z.number().optional(),
277	        maxUses: z.number().optional(),
278	      })
279	    )
280	    .mutation(async ({ ctx, input }) => {
281	      // Only owner/admin can create invites
282	      if (ctx.membership.role !== "owner" && ctx.membership.role !== "admin") {
283	        throw new TRPCError({
284	          code: "FORBIDDEN",
285	          message: "Only owners and admins can create invite links",
286	        });
287	      }
288	
289	      const code = generateInviteCode();
290	      const expiresAt = input.expiresInDays
291	        ? new Date(Date.now() + input.expiresInDays * 24 * 60 * 60 * 1000)
292	        : null;
293	
294	      const [invite] = await db
295	        .insert(organizationInvites)
296	        .values({
297	          organizationId: ctx.organization.id,
298	          code,
299	          role: input.role,
300	          createdBy: ctx.userId!,
301	          expiresAt,
302	          maxUses: input.maxUses ?? null,
303	        })
304	        .returning();
305	
306	      return invite;
307	    }),
308	
309	  // Get all invite links for organization
310	  getInviteLinks: organizationProcedure.query(async ({ ctx }) => {
311	    return await db.query.organizationInvites.findMany({
312	      where: eq(organizationInvites.organizationId, ctx.organization.id),
313	      with: {
314	        creator: true,
315	      },
316	      orderBy: (invites, { desc }) => [desc(invites.createdAt)],
317	    });
318	  }),
